assignments.value:
={{ 
$('Aggregate1').item.json.data
  .map(f => {

    const shortSummary = (f.summary || '')
      .replace(/\n/g, ' ')
      .slice(0, 300);

    const exp = (f.experiences || [])
      .slice(0,5)
      .map(e => {
        const period = `${e.starts_at || ''}${e.ends_at ? '–' + e.ends_at : ''}`;
        const description = e.description && e.description !== 'empty'
          ? `\n   ▪ ${e.description}`
          : '';
        return `- ${e.title} at ${e.company} (${period})${description}`;
      })
      .join('\n');

    const education = (f.education || [])
      .map(e => `- ${e.degree_name}, ${e.school}`)
      .join('\n');

    return `FOUNDER: ${f.full_name}
Location: ${f.country}
Followers: ${f.follower_count}

Profile Summary:
${shortSummary}

Top Experience:
${exp}

Education:
${education}`;
  })
  .join('\n\n----------------------\n\n')
}}

