Market and company info:
{{ $json['Market data'] }}

parameters.jsonBody:
={{
{
  startUrls: ($json["Founder Linkedins"] || "")
  .split(",")
  .map(u => u.replace(/[\u200B-\u200D\uFEFF\u2060]/g, "").trim()) // remove invisible chars + trim
  .filter(u => /^https?:\/\/.+/i.test(u))
  .map((u, i) => ({ url: u, id: String(i + 1) }))
}
}}

